INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (71, 'Ensino Fundamental: Anos Finais', 'Língua Portuguesa', '6º Ano', NULL, 'AE4', 'Aplicar regras de ortografia e pontuação ao escrever textos, de acordo com as convenções da língua escrita.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (72, 'Ensino Fundamental: Anos Finais', 'Língua Portuguesa', '6º Ano', NULL, 'AE5', 'Utilizar diferentes estratégias de leitura em textos literários diversos, inferindo informações implícitas e analisando efeitos de sentido.', NOW());
