INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (83, 'Ensino Fundamental: Anos Finais', 'Língua Portuguesa', '7º Ano', NULL, 'AE4', 'Comparar informações sobre um mesmo fato divulgadas por diferentes veículos e mídias, identificando elementos que contribuem para a credibilidade.', NOW());
