INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (106, 'Ensino Fundamental: Anos Finais', 'Língua Portuguesa', '9º Ano', NULL, 'AE9', 'Analisar diferentes práticas de interação digital para participar de forma ética e crítica em ambientes digitais.', NOW());
