INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (123, 'Ensino Médio', 'Língua Portuguesa', '2ª Série', NULL, 'AE7', 'Produzir comentários apreciativos e críticos sobre obras artísticas diversas, garantindo crítica fundamentada por meio de gêneros multimodais.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (124, 'Ensino Médio', 'Língua Portuguesa', '2ª Série', NULL, 'AE8', 'Analisar os efeitos de sentido decorrentes de escolhas linguísticas e da relação entre textos.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (125, 'Ensino Médio', 'Língua Portuguesa', '2ª Série', NULL, 'AE9', 'Relacionar textos a seus contextos de produção, identificando suas condições de produção e função social.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (126, 'Ensino Médio', 'Língua Portuguesa', '2ª Série', NULL, 'AE10', 'Analisar diferentes estratégias de persuasão e os efeitos de sentido construídos pelo uso de imagens, textos verbais e outros elementos usados para persuadir.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (127, 'Ensino Médio', 'Língua Portuguesa', '2ª Série', NULL, 'AE11', 'Analisar as assimilações, rupturas e permanências na constituição da literatura brasileira, identificando as peculiaridades estruturais e estilísticas de diferentes gêneros literários de cada período.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (128, 'Ensino Médio', 'Língua Portuguesa', '2ª Série', NULL, 'AE12', 'Utilizar variadas ferramentas de apoio a apresentações orais, considerando a clareza de conteúdo criado.', NOW());
