INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (130, 'Ensino Médio', 'Língua Portuguesa', '3ª Série', NULL, 'AE2', 'Avaliar obras da literatura brasileira, de expressão portuguesa, indígena, africana e latino-americana, considerando culturas e povos relacionados, reconhecendo sua importância para a construção de uma identidade nacional.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (131, 'Ensino Médio', 'Língua Portuguesa', '3ª Série', NULL, 'AE3', 'Analisar as peculiaridades estruturais e estilísticas de diferentes gêneros literários, identificando o estilo, os temas e as influências dos movimentos literários aos quais pertencem.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (132, 'Ensino Médio', 'Língua Portuguesa', '3ª Série', NULL, 'AE4', 'Avaliar os percursos argumentativos presentes em textos diversos, para posicionar-se de forma fundamentada e ética frente a questões de relevância social e cultural.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (133, 'Ensino Médio', 'Língua Portuguesa', '3ª Série', NULL, 'AE5', 'Analisar textos de divulgação científica, avaliando suas fontes e reconhecendo enfoques de forma crítica e fundamentada para identificar e descartar fontes não confiáveis.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (134, 'Ensino Médio', 'Língua Portuguesa', '3ª Série', NULL, 'AE6', 'Analisar textos jornalísticos, identificando elementos composicionais, linguagem e função do gênero, por meio do uso de ferramentas de curadoria.', NOW());
