INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (136, 'Ensino Médio', 'Língua Portuguesa', '3ª Série', NULL, 'AE8', 'Analisar diferentes obras e gêneros, identificando aspectos do contexto histórico, social e político, para reconhecer as relações de intertextualidade e de interdiscursividade existentes entre elas.', NOW());
