INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (163, 'Ensino Fundamental: Anos Finais', 'Geografia', '6º Ano', NULL, 'AE1', 'Descrever paisagens a partir de seus elementos constitutivos, comparando as modificações dos lugares de vivência em diferentes tempos.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (164, 'Ensino Fundamental: Anos Finais', 'Geografia', '6º Ano', NULL, 'AE2', 'Relacionar os processos de urbanização, industrialização e desenvolvimento da agropecuária às transformações observadas nas paisagens, reconhecendo as diferentes formas de organização do espaço e as mudanças na interação entre sociedade e natureza.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (165, 'Ensino Fundamental: Anos Finais', 'Geografia', '6º Ano', NULL, 'AE3', 'Examinar as representações cartográficas, reconhecendo a importância da Cartografia como forma de linguagem para a interpretação do espaço, diferenciando os elementos de mapas com diferentes representações e escalas.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (166, 'Ensino Fundamental: Anos Finais', 'Geografia', '6º Ano', NULL, 'AE4', 'Classificar os principais tipos climáticos em diferentes lugares, com base em climogramas e mapas, explicando a diferença entre tempo e clima e a influência da circulação atmosférica.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (167, 'Ensino Fundamental: Anos Finais', 'Geografia', '7º Ano', NULL, 'AE1', 'Comparar as regiões brasileiras em diferentes tempos, utilizando indicadores e representações (gráficos e mapas temáticos), relacionando desigualdades socioeconômicas e processos migratórios.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (168, 'Ensino Fundamental: Anos Finais', 'Geografia', '7º Ano', NULL, 'AE2', 'Analisar como os fluxos econômicos e populacionais contribuem para a formação do território brasileiro e para o surgimento de tensões e conflitos, especialmente em São Paulo, com base em mapas temáticos.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (169, 'Ensino Fundamental: Anos Finais', 'Geografia', '7º Ano', NULL, 'AE3', 'Analisar a distribuição territorial da população brasileira, relacionando os indicadores demográficos e considerando as diversidades étnico-raciais e culturais.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (170, 'Ensino Fundamental: Anos Finais', 'Geografia', '7º Ano', NULL, 'AE4', 'Analisar o papel das redes de transporte e comunicação, explicando a evolução histórica e tecnológica dos fluxos materiais e imateriais em diferentes escalas.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (171, 'Ensino Fundamental: Anos Finais', 'Geografia', '7º Ano', NULL, 'AE5', 'Relacionar os processos de industrialização e inovação tecnológica às transformações socioeconômicas, políticas, culturais e ambientais no território brasileiro.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (172, 'Ensino Fundamental: Anos Finais', 'Geografia', '8º Ano', NULL, 'AE1', 'Analisar a influência política, econômica, social e cultural da Nova Ordem Mundial estabelecida no pós-Segunda Guerra sobre os Estados Unidos, a América Latina, a África, com destaque para o Brasil.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (173, 'Ensino Fundamental: Anos Finais', 'Geografia', '8º Ano', NULL, 'AE2', 'Analisar os conflitos e as tensões geopolíticas contemporâneas na América e na África, aplicando os conceitos de Estado, nação, território, governo e país.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (174, 'Ensino Fundamental: Anos Finais', 'Geografia', '8º Ano', NULL, 'AE3', 'Analisar o papel dos organismos internacionais e regionais na mediação de conflitos em fronteiras latino-americanas, considerando as consequências políticas, econômicas e sociais para a população.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (175, 'Ensino Fundamental: Anos Finais', 'Geografia', '8º Ano', NULL, 'AE4', 'Analisar padrões econômicos e geopolíticos mundiais, relacionando a produção e o intercâmbio dos Estados Unidos e dos BRICS com a atuação de organizações mundiais e blocos econômicos regionais.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (176, 'Ensino Fundamental: Anos Finais', 'Geografia', '8º Ano', NULL, 'AE5', 'Interpretar os efeitos do capital dos Estados Unidos e da China na reorganização das atividades econômicas globais, com destaque para o Brasil.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (177, 'Ensino Fundamental: Anos Finais', 'Geografia', '9º Ano', NULL, 'AE1', 'Analisar o exercício da hegemonia europeia em diferentes tempos e lugares, usando representações cartográficas e gráficas para evidenciar desigualdades sociopolíticas e geopolíticas.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (178, 'Ensino Fundamental: Anos Finais', 'Geografia', '9º Ano', NULL, 'AE2', 'Analisar fatos e situações da integração mundial econômica, política e cultural, comparando características e fenômenos da globalização com os da mundialização.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (179, 'Ensino Fundamental: Anos Finais', 'Geografia', '9º Ano', NULL, 'AE3', 'Comparar regiões da Europa, Ásia e Oceania, a partir de mapas com diferentes projeções, para analisar as desigualdades sociopolíticas e geopolíticas decorrentes da hegemonia europeia.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (180, 'Ensino Fundamental: Anos Finais', 'Geografia', '9º Ano', NULL, 'AE4', 'Investigar a atuação das corporações internacionais e das organizações econômicas mundiais, discutindo suas influências socioeconômicas e culturais no cotidiano das populações em diferentes regiões do mundo.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (181, 'Ensino Médio', 'Geografia', '1ª Série', NULL, 'AE1', 'Analisar os impactos socioambientais das ações humanas coletivas e individuais, selecionando, incorporando e promovendo as que favoreçam a consciência e a ética socioambiental, consumo responsável e a mitigação das mudanças climáticas.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (182, 'Ensino Médio', 'Geografia', '1ª Série', NULL, 'AE2', 'Analisar as relações entre elementos naturais e ações humanas, reconhecendo os impactos e a importância da gestão sustentável da água, do relevo e dos biomas.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (183, 'Ensino Médio', 'Geografia', '1ª Série', NULL, 'AE3', 'Utilizar a linguagem cartográfica de forma crítica e reflexiva.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (184, 'Ensino Médio', 'Geografia', '1ª Série', NULL, 'AE4', 'Avaliar os efeitos da globalização, das transformações tecnológicas e dos blocos econômicos sobre o mundo do trabalho e as condições de vida das diferentes gerações.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (185, 'Ensino Médio', 'Geografia', '1ª Série', NULL, 'AE5', 'Avaliar os impactos socioeconômicos e socioambientais das cadeias produtivas ligadas à exploração de recursos naturais e à agropecuária.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (186, 'Ensino Médio', 'Geografia', '1ª Série', NULL, 'AE6', 'Comparar os impactos socioambientais de diferentes modelos socioeconômicos em escala global, analisando as iniciativas e políticas governamentais voltadas à promoção da sustentabilidade.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (187, 'Ensino Médio', 'Geografia', '2ª Série', NULL, 'AE1', 'Analisar como diferentes regiões se organizam, considerando aspectos culturais, econômicos, ambientais, políticos e sociais, com base em dados demográficos e econômicos.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (188, 'Ensino Médio', 'Geografia', '2ª Série', NULL, 'AE2', 'Analisar transformações econômicas, fluxos migratórios e processos de globalização, especialmente no Brasil, compreendendo suas causas, efeitos e implicações para a economia, a sociedade e as relações internacionais.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (189, 'Ensino Médio', 'Geografia', '2ª Série', NULL, 'AE3', 'Analisar indicadores socioeconômicos do Brasil, relacionando-os às leis trabalhistas e à atuação do país na economia mundial.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (190, 'Ensino Médio', 'Geografia', '2ª Série', NULL, 'AE4', 'Analisar os significados de Estado, nação, território, fronteiras e vazios (espacial, temporal e cultural), considerando a formação histórica, disputas territoriais e identidades culturais, incluindo o contexto brasileiro.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (191, 'Ensino Médio', 'Geografia', '2ª Série', NULL, 'AE5', 'Analisar os processos de urbanização no Brasil e no mundo, relacionando a formação de cidades, megacidades e territórios ao papel de diferentes agentes e aos impactos socioambientais e socioculturais envolvidos.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (192, 'Ensino Médio', 'Geografia', '2ª Série', NULL, 'AE6', 'Avaliar dados de desigualdade no campo e de modelos de produção, identificando políticas públicas e discutindo as características do agronegócio contemporâneo.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (193, 'Ensino Médio', 'Biologia', '1ª Série', NULL, 'AE1', 'Analisar as transformações e conservações de matéria e energia em sistemas biológicos, associando processos celulares e interações ecológicas à sustentabilidade ambiental.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (194, 'Ensino Médio', 'Biologia', '1ª Série', NULL, 'AE2', 'Explicar o aquecimento global, avaliando suas relações com as mudanças climáticas e os riscos ambientais provocados pelas ações humanas.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (195, 'Ensino Médio', 'Biologia', '1ª Série', NULL, 'AE3', 'Analisar os impactos socioambientais das fontes de energia renováveis e não renováveis a partir das matrizes mundial e brasileira.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (196, 'Ensino Médio', 'Biologia', '1ª Série', NULL, 'AE4', 'Reconhecer os impactos da poluição ambiental nos sistemas fisiológicos humanos, identificando ações e tecnologias voltadas à prevenção e promoção da saúde individual, coletiva e ambiental.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (197, 'Ensino Médio', 'Biologia', '2ª Série', NULL, 'AE1', 'Reconhecer os riscos e benefícios das radiações para a saúde humana.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (198, 'Ensino Médio', 'Biologia', '2ª Série', NULL, 'AE2', 'Relacionar a meiose à reprodução e a mitose ao crescimento, manutenção dos tecidos e origem de cânceres.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (199, 'Ensino Médio', 'Biologia', '2ª Série', NULL, 'AE3', 'Avaliar os efeitos de intervenções humanas nos ecossistemas, destacando seus impactos sobre a biodiversidade e propondo ações voltadas à sustentabilidade e prevenção de zoonoses.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (200, 'Ensino Médio', 'Biologia', '2ª Série', NULL, 'AE4', 'Avaliar os benefícios e riscos dos defensivos agrícolas, relacionando sua composição, toxicidade e exposição aos processos de bioacumulação e biomagnificação.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (201, 'Ensino Médio', 'Biologia', '2ª Série', NULL, 'AE5', 'Analisar a importância da diversidade genética, discutindo sua relação com organismos geneticamente modificados e transgênicos, considerando os princípios de biossegurança, bioética e biodiversidade.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (202, 'Ensino Fundamental: Anos Finais', 'Ciências', '6º Ano', NULL, 'AE1', 'Descrever as esferas que compõem a Terra, reconhecendo o surgimento da litosfera e suas transformações ao longo do tempo.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (203, 'Ensino Fundamental: Anos Finais', 'Ciências', '6º Ano', NULL, 'AE2', 'Explicar os efeitos dos movimentos do Sistema Terra-Sol-Lua na ocorrência de fenômenos naturais, considerando as relações entre rotação e translação da Terra e a interação entre Sol e Lua.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (204, 'Ensino Fundamental: Anos Finais', 'Ciências', '6º Ano', NULL, 'AE3', 'Classificar os tipos de rochas, identificando seus processos de formação e transformação do solo, como a fossilização em rochas sedimentares.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (205, 'Ensino Fundamental: Anos Finais', 'Ciências', '6º Ano', NULL, 'AE4', 'Analisar os processos de separação de misturas do cotidiano, classificando as substâncias, as misturas e as mudanças de estado físico da matéria.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (206, 'Ensino Fundamental: Anos Finais', 'Ciências', '7º Ano', NULL, 'AE1', 'Investigar a teoria da deriva continental, relacionando a correspondência entre os formatos das costas brasileira e africana aos processos da tectônica de placas.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (207, 'Ensino Fundamental: Anos Finais', 'Ciências', '7º Ano', NULL, 'AE2', 'Identificar a composição da atmosfera e os fatores naturais e humanos que a modificam, relacionando-os aos impactos ambientais e à saúde do sistema respiratório humano.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (208, 'Ensino Fundamental: Anos Finais', 'Ciências', '7º Ano', NULL, 'AE3', 'Distinguir o uso e o funcionamento de máquinas simples, com base no conceito de força e exemplos do cotidiano.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (209, 'Ensino Fundamental: Anos Finais', 'Ciências', '7º Ano', NULL, 'AE4', 'Aplicar os conceitos de calor, temperatura e sensação térmica na análise das formas de propagação do calor e do equilíbrio termodinâmico.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (210, 'Ensino Fundamental: Anos Finais', 'Ciências', '7º Ano', NULL, 'AE5', 'Analisar os impactos econômicos, culturais e sociais das inovações tecnológicas na sociedade, destacando as máquinas elétricas e seu uso consciente.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (211, 'Ensino Fundamental: Anos Finais', 'Ciências', '7º Ano', NULL, 'AE6', 'Analisar os impactos socioambientais do uso de combustíveis fósseis, das queimadas e do desmatamento, reconhecendo suas consequências para os ecossistemas.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (212, 'Ensino Fundamental: Anos Finais', 'Ciências', '7º Ano', NULL, 'AE7', 'Identificar o efeito estufa como um fenômeno natural, reconhecendo os impactos das ações humanas que o intensificam.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (213, 'Ensino Fundamental: Anos Finais', 'Ciências', '7º Ano', NULL, 'AE8', 'Explicar as características de vírus, bactérias e fungos, identificando as doenças que causam e as formas de preveni-las.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (214, 'Ensino Fundamental: Anos Finais', 'Ciências', '7º Ano', NULL, 'AE9', 'Caracterizar os ecossistemas brasileiros, explicando como os fatores bióticos e abióticos se relacionam às características da fauna e da flora, considerando a biodiversidade como elemento central.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (215, 'Ensino Fundamental: Anos Finais', 'Ciências', '8º Ano', NULL, 'AE1', 'Identificar as mudanças físicas e comportamentais que ocorrem na puberdade, relacionando-as às interações entre os sistemas nervoso e endócrino.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (216, 'Ensino Fundamental: Anos Finais', 'Ciências', '8º Ano', NULL, 'AE2', 'Comparar processos reprodutivos assexuados e sexuados em vegetais e animais, com base em mecanismos evolutivos e adaptativos.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (217, 'Ensino Fundamental: Anos Finais', 'Ciências', '8º Ano', NULL, 'AE3', 'Analisar formas de prevenção das infecções sexualmente transmissíveis e da gravidez precoce, reconhecendo práticas de saúde sexual e reprodutiva.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (218, 'Ensino Fundamental: Anos Finais', 'Ciências', '8º Ano', NULL, 'AE4', 'Discutir os efeitos do uso de substâncias psicoativas para propor ações de prevenção voltadas à saúde individual e coletiva.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (219, 'Ensino Fundamental: Anos Finais', 'Ciências', '8º Ano', NULL, 'AE5', 'Descrever as principais estruturas e funções do sistema digestório e dos nutrientes, relacionando-os à classificação dos alimentos em processados, ultraprocessados e in natura.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (220, 'Ensino Fundamental: Anos Finais', 'Ciências', '8º Ano', NULL, 'AE6', 'Explicar o funcionamento do sistema respiratório e os fatores que comprometem sua atividade, incluindo a poluição atmosférica e as doenças.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (221, 'Ensino Fundamental: Anos Finais', 'Ciências', '8º Ano', NULL, 'AE7', 'Explicar o funcionamento do sistema circulatório e sua relação com o sistema imune, reconhecendo ações que contribuem para a prevenção de doenças.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (222, 'Ensino Fundamental: Anos Finais', 'Ciências', '9º Ano', NULL, 'AE1', 'Analisar a importância do acesso a informações científicas de qualidade, considerando os critérios de confiabilidade das fontes e avaliando os impactos da desinformação.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (223, 'Ensino Fundamental: Anos Finais', 'Ciências', '9º Ano', NULL, 'AE2', 'Identificar os modelos que estruturam a matéria, reconhecendo a evolução histórica dos modelos atômicos e a classificação dos elementos químicos.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (224, 'Ensino Fundamental: Anos Finais', 'Ciências', '9º Ano', NULL, 'AE3', 'Explicar as mudanças de estado físico, relacionando-as à estrutura molecular, aos estados de organização da matéria e às temperaturas de fusão e ebulição.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (225, 'Ensino Fundamental: Anos Finais', 'Ciências', '9º Ano', NULL, 'AE4', 'Analisar as transformações químicas e as relações entre reagentes e produtos, aplicando as leis ponderais.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (226, 'Ensino Fundamental: Anos Finais', 'Ciências', '9º Ano', NULL, 'AE5', 'Classificar as radiações eletromagnéticas de acordo com suas frequências e aplicações em diferentes tecnologias, reconhecendo suas implicações para a saúde e para o cotidiano.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (227, 'Ensino Fundamental: Anos Finais', 'Ciências', '9º Ano', NULL, 'AE6', 'Investigar as características das ondas mecânicas e eletromagnéticas, reconhecendo como esses conhecimentos revolucionaram os sistemas de comunicação humana.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (228, 'Ensino Fundamental: Anos Finais', 'Ciências', '9º Ano', NULL, 'AE7', 'Explicar os processos de hereditariedade e as aplicações da biotecnologia, articulando-os à genética clássica e à evolução biológica.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (229, 'Ensino Fundamental: Anos Finais', 'Ciências', '9º Ano', NULL, 'AE8', 'Explicar a transmissão das características hereditárias com base nas ideias de Mendel sobre fatores hereditários, gametas, segregação e fecundação, utilizando heredogramas.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (230, 'Ensino Fundamental: Anos Finais', 'Ciências', '9º Ano', NULL, 'AE9', 'Explicar as ideias evolucionistas de Lamarck e Darwin, destacando seus contextos históricos e sua relevância para a compreensão da biodiversidade.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (231, 'Ensino Médio', 'Filosofia', '1ª Série', NULL, 'AE1', 'Analisar as origens da Filosofia, seus campos de investigação e as características da atitude filosófica, considerando a importância do diálogo e da argumentação fundamentada.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (232, 'Ensino Médio', 'Filosofia', '1ª Série', NULL, 'AE2', 'Analisar a produção artística, compreendendo a formação do gosto e exercitando a atitude crítica diante de padrões estéticos, conhecimentos e valores historicamente construídos.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (233, 'Ensino Médio', 'Filosofia', '1ª Série', NULL, 'AE3', 'Analisar as relações intergeracionais no Brasil e no mundo contemporâneo, problematizando estereótipos e a prática do etarismo, e reconhecendo a importância dos estatutos de proteção às diferentes fases da vida.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (234, 'Ensino Médio', 'Filosofia', '1ª Série', NULL, 'AE4', 'Identificar formas de violência, suas causas e significados, avaliando mecanismos de enfrentamento com base em argumentos éticos.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (235, 'Ensino Médio', 'Filosofia', '1ª Série', NULL, 'AE5', 'Analisar a formação do Estado e a legitimidade do poder político, aplicando o conceito de soberania a partir de pensadores do contratualismo, liberalismo e republicanismo clássicos.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (236, 'Ensino Médio', 'Física', '1ª Série', NULL, 'AE1', 'Resolver problemas envolvendo corpos em movimento com velocidade e/ou aceleração constantes, representando trajetória, posição, velocidade e aceleração por meio de funções, gráficos e tabelas.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (237, 'Ensino Médio', 'Física', '1ª Série', NULL, 'AE2', 'Analisar situações de equilíbrio e de movimento acelerado, aplicando grandezas escalares e vetoriais com operações algébricas e vetoriais, com base nas Leis de Newton.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (238, 'Ensino Médio', 'Física', '1ª Série', NULL, 'AE3', 'Aplicar os princípios de conservação da energia e da quantidade de movimento na análise de sistemas mecânicos que envolvem trabalho, potência, impulso e colisões.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (239, 'Ensino Médio', 'Física', '2ª Série', NULL, 'AE1', 'Interpretar sistemas térmicos, aplicando leis e modelos da Termodinâmica para descrever as transformações de energia associadas à transferência de calor e às variações de temperatura.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (240, 'Ensino Médio', 'Física', '2ª Série', NULL, 'AE2', 'Aplicar princípios da Termodinâmica na análise, avaliação e construção de sistemas térmicos, relacionando sua eficiência a contextos de uso sustentável da energia.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (241, 'Ensino Médio', 'Física', '3ª Série', NULL, 'AE1', 'Analisar interações eletrostáticas entre cargas e campos elétricos, calculando forças, potenciais e energia associada a situações práticas e simuladas.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (242, 'Ensino Médio', 'Física', '3ª Série', NULL, 'AE2', 'Analisar circuitos elétricos, calculando corrente, resistência, tensão, potência e consumo de energia.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (243, 'Ensino Médio', 'Química', '1ª Série', NULL, 'AE1', 'Analisar a evolução histórica e científica dos modelos atômicos, reconhecendo-os como uma construção humana e compreendendo como eles explicam fenômenos do cotidiano.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (244, 'Ensino Médio', 'Química', '1ª Série', NULL, 'AE2', 'Analisar a origem, a classificação e a organização dos elementos químicos na Tabela Periódica, reconhecendo as características dos radioisótopos e as leis das emissões radioativas.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (245, 'Ensino Médio', 'Química', '1ª Série', NULL, 'AE3', 'Analisar as diversas interações entre átomos, entre moléculas e entre átomos e moléculas, bem como seus efeitos nas propriedades dos materiais, distinguindo as ligações químicas e as interações intermoleculares das moléculas essenciais à vida.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (246, 'Ensino Médio', 'Química', '1ª Série', NULL, 'AE4', 'Analisar situações-problema em processos tecnológicos, produtivos, sustentáveis e ambientais, reconhecendo a quantidade de matéria e energia envolvidas nas transformações químicas.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (247, 'Ensino Médio', 'Química', '2ª Série', NULL, 'AE1', 'Analisar a composição, as propriedades e as aplicações dos metais pesados e dos plásticos para avaliar os impactos socioambientais e os riscos à saúde decorrentes de sua extração, produção e descarte inadequado.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (248, 'Ensino Médio', 'Química', '2ª Série', NULL, 'AE2', 'Analisar a eficiência e os impactos socioambientais dos combustíveis renováveis e não renováveis, calculando a entalpia das reações químicas e identificando a dependência mundial dos combustíveis não renováveis.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (249, 'Ensino Médio', 'Química', '2ª Série', NULL, 'AE3', 'Analisar os compostos orgânicos e as suas aplicações, nomeando, classificando e identificando as funções orgânicas, para elaborar ações de prevenção e de promoção da saúde e do bem-estar.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (250, 'Ensino Médio', 'Química', '2ª Série', NULL, 'AE4', 'Analisar caso de isomeria plana nos macro e micronutrientes, identificando as propriedades e as vantagens e desvantagens do uso dos compostos orgânicos na produção de alimentos.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (251, 'Ensino Médio', 'Química', '2ª Série', NULL, 'AE5', 'Analisar a estrutura, a síntese e as aplicações de polímeros naturais e sintéticos, identificando as principais reações de polimerização e casos de isomeria cis-trans.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (252, 'Ensino Médio', 'Sociologia', '2ª Série', NULL, 'AE1', 'Analisar a especificidade do conhecimento sociológico como campo científico, reconhecendo seus conceitos fundamentais e teorias clássicas da relação entre indivíduo e sociedade, aplicando-os na análise de processos sociais.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (253, 'Ensino Médio', 'Sociologia', '2ª Série', NULL, 'AE2', 'Analisar a relação entre o indivíduo e o contexto sociocultural em que vive, aplicando conceitos da antropologia e da sociologia, identificando os processos que tornam os humanos seres sociais e culturais.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (254, 'Ensino Médio', 'Sociologia', '2ª Série', NULL, 'AE3', 'Elaborar hipóteses e argumentos a partir da análise de evidências de processos sociais, culturais e políticos, de informações confiáveis e da coleta e sistematização de dados.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (255, 'Ensino Médio', 'Sociologia', '2ª Série', NULL, 'AE4', 'Analisar as relações entre sujeitos e grupos no mundo contemporâneo, aplicando os conceitos de diferenciação, produção social da diferença, estratificação e classe social, para explicar problemas de convivência, exclusão social, marginalização e desigualdades.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (256, 'Ensino Médio', 'Sociologia', '2ª Série', NULL, 'AE5', 'Analisar as diferentes formas de violência presentes no cotidiano, compreendendo suas causas sociais, culturais e institucionais e discutindo seus impactos na convivência social.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (257, 'Ensino Médio', 'Sociologia', '2ª Série', NULL, 'AE6', 'Analisar situações da vida cotidiana, estilos de vida, valores e condutas, aplicando conceitos sociológicos, para desnaturalizar formas de desigualdade, preconceito, intolerância, discriminação e violência presentes nas relações étnico-raciais, de gênero e em outros contextos sociais.', NOW());
INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES (258, 'Ensino Médio', 'Sociologia', '2ª Série', NULL, 'AE7', 'Analisar os princípios dos Direitos Humanos, como a dignidade humana, a igualdade e a não violência, para identificar práticas cotidianas de violação e avaliar ações que promovem a defesa desses direitos.', NOW());
